import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // [[1,5,9],[2,3,8],[4]] k=5 -> [1,2,3,4,5]
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{1,5,9},{2,3,8},{4}}, 5);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5}, result);
        assertEquals(5, result.length); // size check
    }

    @Test
    void kLargerThanTotal() {
        // total = 4, k = 10 -> return all 4 elements sorted
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{1,3},{2,4}}, 10);
        assertArrayEquals(new int[]{1, 2, 3, 4}, result);
        assertEquals(4, result.length); // bounded by actual total
    }

    @Test
    void kEqualsOne() {
        // smallest single element across all streams
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{5,8},{1,9},{3}}, 1);
        assertArrayEquals(new int[]{1}, result);
    }

    @Test
    void emptyInnerStream() {
        // src1 is empty — must not crash; k=3 from remaining elements
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{1,2,5},{},{3,4}}, 3);
        assertArrayEquals(new int[]{1, 2, 3}, result);
        assertEquals(3, result.length);
    }

    @Test
    void singleSource() {
        // k=1 single stream behaves as a prefix slice
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{10, 20, 30}}, 2);
        assertArrayEquals(new int[]{10, 20}, result);
    }

    @Test
    void tiebreakerExercised() {
        // src0 and src1 both have 2 at front; src0 extracted first (lower index)
        // k=3 -> [2,2,5]
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{2,5},{2,8}}, 3);
        assertArrayEquals(new int[]{2, 2, 5}, result);
        assertEquals(3, result.length);
    }

    @Test
    void allStreamsEmpty() {
        // no elements at all; k irrelevant -> empty result
        int[] result = new Solution().smallestKAcrossStreams(
            new int[][]{{},{},{}}, 5);
        assertArrayEquals(new int[]{}, result);
        assertEquals(0, result.length);
    }
}
